#!/usr/bin/env Rscript
#
# Experiment 20: stress checks for normal-theory FIML alpha on ordinal MAR data.
#
# The paper simulation makes normal FIML look surprisingly good when scored
# ordinal data are generated by a balanced Gaussian copula and MAR depends
# smoothly on an observed anchor item. This runner keeps n small and changes the
# margins, latent distribution, and MAR shape to see whether that good behavior
# survives less normal-looking but still plausible item-response regimes.

suppressPackageStartupMessages({
  library(misskappa)
})

usage <- function(status = 0L) {
  cat(paste0(
    "Usage: Rscript run_experiment.R [options]\n\n",
    "Options:\n",
    "  --help, -h          Show this help and exit.\n",
    "  --smoke             Cheap check: n=100, reps=8, all default cells.\n",
    "  --reps N            Replications per cell. Default: 200.\n",
    "  --n N               Sample size. Default: 100.\n",
    "  --dgps CSV          DGPs. Default: gauss_balanced,gauss_skew,class_skew,anchor_heterocov.\n",
    "  --mechanisms CSV    Missingness. Default: mcar30,mar_linear30,mar_lowgate45.\n",
    "  --methods CSV       Methods. Default: pairwise,cat_fiml,normal_fiml,listwise.\n",
    "  --seed-base N       Base seed. Default: 20200620.\n",
    "  --out-dir PATH      Output directory. Default: script-local results/.\n",
    "  --progress          Print one line per design cell.\n\n",
    "Examples:\n",
    "  Rscript run_experiment.R --smoke --progress\n",
    "  Rscript run_experiment.R --reps 200 --n 100 --progress\n"
  ))
  quit(save = "no", status = status)
}

script_dir <- local({
  cmd <- commandArgs(FALSE)
  file_arg <- grep("^--file=", cmd, value = TRUE)
  if (length(file_arg) == 0L) getwd()
  else dirname(normalizePath(sub("^--file=", "", file_arg[[1L]]), mustWork = FALSE))
})

parse_csv_chr <- function(x) trimws(strsplit(x, ",", fixed = TRUE)[[1L]])

parse_args <- function(argv) {
  opts <- list(
    smoke = FALSE,
    reps = 200L,
    n = 100L,
    dgps = c("gauss_balanced", "gauss_skew", "class_skew", "anchor_heterocov"),
    mechanisms = c("mcar30", "mar_linear30", "mar_lowgate45"),
    methods = c("pairwise", "cat_fiml", "normal_fiml", "listwise"),
    seed_base = 20200620L,
    out_dir = file.path(script_dir, "results"),
    progress = FALSE
  )
  explicit <- list(reps = FALSE, n = FALSE)

  i <- 1L
  while (i <= length(argv)) {
    arg <- argv[[i]]
    if (arg %in% c("--help", "-h")) usage(0L)
    if (arg == "--smoke") {
      opts$smoke <- TRUE
      i <- i + 1L
      next
    }
    if (arg == "--progress") {
      opts$progress <- TRUE
      i <- i + 1L
      next
    }
    needs_value <- c("--reps", "--n", "--dgps", "--mechanisms",
                     "--methods", "--seed-base", "--out-dir")
    if (arg %in% needs_value) {
      if (i == length(argv)) stop(arg, " needs a value.", call. = FALSE)
      val <- argv[[i + 1L]]
      if (arg == "--reps") {
        opts$reps <- as.integer(val); explicit$reps <- TRUE
      } else if (arg == "--n") {
        opts$n <- as.integer(val); explicit$n <- TRUE
      } else if (arg == "--dgps") {
        opts$dgps <- parse_csv_chr(val)
      } else if (arg == "--mechanisms") {
        opts$mechanisms <- parse_csv_chr(val)
      } else if (arg == "--methods") {
        opts$methods <- parse_csv_chr(val)
      } else if (arg == "--seed-base") {
        opts$seed_base <- as.integer(val)
      } else if (arg == "--out-dir") {
        opts$out_dir <- val
      }
      i <- i + 2L
      next
    }
    stop("Unknown argument: ", arg, call. = FALSE)
  }

  if (opts$smoke) {
    if (!explicit$reps) opts$reps <- 8L
    if (!explicit$n) opts$n <- 100L
  }

  if (is.na(opts$reps) || opts$reps < 1L) stop("--reps must be >= 1.", call. = FALSE)
  if (is.na(opts$n) || opts$n < 20L) stop("--n must be >= 20.", call. = FALSE)
  if (is.na(opts$seed_base)) stop("--seed-base must be an integer.", call. = FALSE)
  opts
}

opts <- parse_args(commandArgs(trailingOnly = TRUE))

alpha_from_sigma <- function(Sigma) {
  p <- ncol(Sigma)
  (p / (p - 1)) * (1 - sum(diag(Sigma)) / sum(Sigma))
}

thresholds_from_probs <- function(probs) {
  stats::qnorm(cumsum(probs)[-length(probs)])
}

bvn_rect_prob <- function(xlo, xhi, ylo, yhi, rho) {
  if (abs(rho) < 1e-12) {
    return((stats::pnorm(xhi) - stats::pnorm(xlo)) *
             (stats::pnorm(yhi) - stats::pnorm(ylo)))
  }
  s <- sqrt(1 - rho * rho)
  integrand <- function(x) {
    stats::dnorm(x) *
      (stats::pnorm((yhi - rho * x) / s) -
         stats::pnorm((ylo - rho * x) / s))
  }
  stats::integrate(
    integrand, lower = xlo, upper = xhi, rel.tol = 1e-10,
    abs.tol = 1e-12, subdivisions = 200L
  )$value
}

ordinal_cov_from_latent <- local({
  cache <- new.env(parent = emptyenv())
  function(rho, probs) {
    scores <- seq_along(probs) - 1L
    score_mean <- sum(probs * scores)
    key <- paste(sprintf("%.12f", rho), paste(probs, collapse = ","), sep = "|")
    if (exists(key, cache, inherits = FALSE)) return(get(key, cache, inherits = FALSE))
    thresholds <- thresholds_from_probs(probs)
    lower <- c(-Inf, thresholds)
    upper <- c(thresholds, Inf)
    joint <- matrix(0, length(scores), length(scores))
    for (a in seq_along(scores)) {
      for (b in seq_along(scores)) {
        joint[a, b] <- bvn_rect_prob(lower[a], upper[a], lower[b], upper[b], rho)
      }
    }
    cov <- sum(outer(scores, scores) * joint) - score_mean^2
    assign(key, cov, cache)
    cov
  }
})

congeneric_latent <- function() {
  lambda <- c(0.35, 0.45, 0.55, 0.65, 0.75, 0.85)
  R <- tcrossprod(lambda)
  diag(R) <- 1
  R
}

gaussian_sigma <- function(probs, latent) {
  scores <- seq_along(probs) - 1L
  score_mean <- sum(probs * scores)
  score_var <- sum(probs * (scores - score_mean)^2)
  p <- ncol(latent)
  Sigma <- matrix(0, p, p)
  diag(Sigma) <- score_var
  for (j in seq_len(p - 1L)) {
    for (k in (j + 1L):p) {
      Sigma[j, k] <- ordinal_cov_from_latent(latent[j, k], probs)
      Sigma[k, j] <- Sigma[j, k]
    }
  }
  Sigma
}

simulate_gaussian <- function(n, probs, latent) {
  thresholds <- thresholds_from_probs(probs)
  z <- matrix(stats::rnorm(n * ncol(latent)), n, ncol(latent)) %*% chol(latent)
  x <- apply(z, 2L, function(col) findInterval(col, thresholds))
  matrix(as.integer(x), nrow = n, ncol = ncol(latent))
}

class_probs <- c(0.70, 0.30)
class_low <- rbind(
  c(0.80, 0.15, 0.05),
  c(0.75, 0.20, 0.05),
  c(0.70, 0.23, 0.07),
  c(0.72, 0.22, 0.06),
  c(0.68, 0.25, 0.07),
  c(0.66, 0.27, 0.07)
)
class_high <- rbind(
  c(0.25, 0.40, 0.35),
  c(0.20, 0.38, 0.42),
  c(0.18, 0.37, 0.45),
  c(0.22, 0.36, 0.42),
  c(0.16, 0.34, 0.50),
  c(0.14, 0.33, 0.53)
)

anchor_group_probs <- c(0.45, 0.35, 0.20)
anchor_target_probs <- rbind(
  c(0.70, 0.25, 0.05),
  c(0.35, 0.45, 0.20),
  c(0.15, 0.35, 0.50)
)
anchor_target_rho <- c(0.75, 0.35, 0.05)

class_sigma <- function() {
  scores <- 0:2
  probs_by_class <- list(class_low, class_high)
  p <- nrow(class_low)
  means_by_class <- matrix(0, length(class_probs), p)
  second_by_class <- matrix(0, length(class_probs), p)
  for (c in seq_along(class_probs)) {
    probs <- probs_by_class[[c]]
    means_by_class[c, ] <- probs %*% scores
    second_by_class[c, ] <- probs %*% (scores^2)
  }
  means <- as.numeric(class_probs %*% means_by_class)
  seconds <- as.numeric(class_probs %*% second_by_class)
  Sigma <- matrix(0, p, p)
  diag(Sigma) <- seconds - means^2
  for (j in seq_len(p - 1L)) {
    for (k in (j + 1L):p) {
      cross <- sum(class_probs * means_by_class[, j] * means_by_class[, k])
      Sigma[j, k] <- cross - means[j] * means[k]
      Sigma[k, j] <- Sigma[j, k]
    }
  }
  Sigma
}

anchor_heterocov_sigma <- function() {
  scores <- 0:2
  p <- 6L
  anchor_mean <- sum(anchor_group_probs * scores)
  anchor_var <- sum(anchor_group_probs * (scores - anchor_mean)^2)
  target_mu_g <- as.numeric(anchor_target_probs %*% scores)
  target_second_g <- as.numeric(anchor_target_probs %*% (scores^2))
  target_var_g <- target_second_g - target_mu_g^2
  target_cov_g <- vapply(seq_along(anchor_group_probs), function(g) {
    ordinal_cov_from_latent(anchor_target_rho[g], anchor_target_probs[g, ])
  }, numeric(1L))
  target_mean <- sum(anchor_group_probs * target_mu_g)
  target_var <- sum(anchor_group_probs * (target_var_g + target_mu_g^2)) - target_mean^2
  target_cov <- sum(anchor_group_probs * (target_cov_g + target_mu_g^2)) - target_mean^2
  anchor_target_cov <- sum(anchor_group_probs * scores * target_mu_g) -
    anchor_mean * target_mean

  Sigma <- matrix(target_cov, p, p)
  diag(Sigma) <- target_var
  Sigma[1L, ] <- anchor_target_cov
  Sigma[, 1L] <- anchor_target_cov
  Sigma[1L, 1L] <- anchor_var
  dimnames(Sigma) <- NULL
  Sigma
}

simulate_class <- function(n) {
  scores <- 0:2
  probs_by_class <- list(class_low, class_high)
  cls <- sample(seq_along(class_probs), n, replace = TRUE, prob = class_probs)
  x <- matrix(NA_integer_, n, nrow(class_low))
  for (i in seq_len(n)) {
    probs <- probs_by_class[[cls[i]]]
    for (j in seq_len(ncol(x))) {
      x[i, j] <- sample(scores, 1L, prob = probs[j, ])
    }
  }
  x
}

simulate_anchor_heterocov <- function(n) {
  scores <- 0:2
  groups <- sample(seq_along(anchor_group_probs), n, replace = TRUE,
                   prob = anchor_group_probs)
  x <- matrix(NA_integer_, n, 6L)
  x[, 1L] <- groups - 1L
  for (g in seq_along(anchor_group_probs)) {
    idx <- which(groups == g)
    if (!length(idx)) next
    thresholds <- thresholds_from_probs(anchor_target_probs[g, ])
    R <- matrix(anchor_target_rho[g], 5L, 5L)
    diag(R) <- 1
    z <- matrix(stats::rnorm(length(idx) * 5L), length(idx), 5L) %*% chol(R)
    vals <- apply(z, 2L, function(col) findInterval(col, thresholds))
    x[idx, 2:6] <- matrix(as.integer(vals), nrow = length(idx), ncol = 5L)
  }
  x
}

dgp_defs <- list(
  gauss_balanced = list(
    label = "Gaussian copula, balanced ordinal margins",
    family = "gaussian_copula",
    categories = 3L,
    probs = c(0.20, 0.50, 0.30),
    simulate = function(n) simulate_gaussian(n, c(0.20, 0.50, 0.30), congeneric_latent()),
    sigma = function() gaussian_sigma(c(0.20, 0.50, 0.30), congeneric_latent())
  ),
  gauss_skew = list(
    label = "Gaussian copula, skewed ordinal margins",
    family = "gaussian_copula_skewed",
    categories = 3L,
    probs = c(0.65, 0.25, 0.10),
    simulate = function(n) simulate_gaussian(n, c(0.65, 0.25, 0.10), congeneric_latent()),
    sigma = function() gaussian_sigma(c(0.65, 0.25, 0.10), congeneric_latent())
  ),
  class_skew = list(
    label = "Latent class, skewed ordinal margins",
    family = "latent_class_skewed",
    categories = 3L,
    probs = NA,
    simulate = simulate_class,
    sigma = class_sigma
  ),
  anchor_heterocov = list(
    label = "Anchor-group mixture, heterogeneous target covariance",
    family = "anchor_heterocov",
    categories = 3L,
    probs = NA,
    simulate = simulate_anchor_heterocov,
    sigma = anchor_heterocov_sigma
  )
)

valid_dgps <- names(dgp_defs)
valid_mechanisms <- c("complete", "mcar30", "mar_linear30", "mar_lowgate45")
valid_methods <- c("pairwise", "cat_fiml", "normal_fiml", "listwise")

if (!all(opts$dgps %in% valid_dgps)) {
  stop("--dgps must contain only: ", paste(valid_dgps, collapse = ","), call. = FALSE)
}
if (!all(opts$mechanisms %in% valid_mechanisms)) {
  stop("--mechanisms must contain only: ", paste(valid_mechanisms, collapse = ","), call. = FALSE)
}
if (!all(opts$methods %in% valid_methods)) {
  stop("--methods must contain only: ", paste(valid_methods, collapse = ","), call. = FALSE)
}
if (!exists("alpha", asNamespace("misskappa"), mode = "function")) {
  stop("misskappa::alpha() is not available; install the categorical alpha package build first.",
       call. = FALSE)
}
if (!exists("alpha_continuous", asNamespace("misskappa"), mode = "function")) {
  stop("misskappa::alpha_continuous() is not available; install the normal-FIML alpha package build first.",
       call. = FALSE)
}

target_items <- function(p) seq.int(2L, p)

apply_mcar <- function(X, rate) {
  out <- X
  for (j in target_items(ncol(X))) {
    out[stats::runif(nrow(X)) < rate, j] <- NA_integer_
  }
  out
}

tune_intercept <- function(z, slope, rate, offset = 0.0) {
  f <- function(a) mean(stats::plogis(a + offset + slope * z)) - rate
  stats::uniroot(f, c(-16, 16))$root
}

apply_anchor_linear_mar <- function(X, rate) {
  out <- X
  z <- as.numeric(scale(X[, 1L]))
  z[!is.finite(z)] <- 0
  slope <- -1.35
  for (j in target_items(ncol(X))) {
    shift <- (j - (ncol(X) + 2) / 2) * 0.08
    a <- tune_intercept(z, slope, rate, shift)
    p_miss <- stats::plogis(a + shift + slope * z)
    out[stats::runif(nrow(X)) < p_miss, j] <- NA_integer_
  }
  out
}

apply_anchor_lowgate_mar <- function(X, rate) {
  out <- X
  low_anchor <- as.numeric(X[, 1L] == min(X[, 1L], na.rm = TRUE))
  slope <- 3.00
  for (j in target_items(ncol(X))) {
    shift <- (j - (ncol(X) + 2) / 2) * 0.08
    a <- tune_intercept(low_anchor, slope, rate, shift)
    p_miss <- stats::plogis(a + shift + slope * low_anchor)
    out[stats::runif(nrow(X)) < p_miss, j] <- NA_integer_
  }
  out
}

apply_missing <- function(X, mechanism) {
  if (mechanism == "complete") return(X)
  if (mechanism == "mcar30") return(apply_mcar(X, 0.30))
  if (mechanism == "mar_linear30") return(apply_anchor_linear_mar(X, 0.30))
  if (mechanism == "mar_lowgate45") return(apply_anchor_lowgate_mar(X, 0.45))
  stop("Unknown mechanism: ", mechanism, call. = FALSE)
}

se_from_fit <- function(fit) {
  v <- as.numeric(stats::vcov(fit)[1L, 1L])
  if (!is.finite(v) || v < 0) return(NA_real_)
  sqrt(v)
}

fit_pairwise <- function(X) {
  fit <- misskappa::alpha(X, method = "available")
  list(estimate = as.numeric(stats::coef(fit)[["alpha"]]),
       se = se_from_fit(fit), iter = NA_integer_)
}

fit_cat_fiml <- function(X) {
  fit <- misskappa::alpha(
    X,
    method = "fiml",
    em_options = list(
      tol = 1e-7,
      max_iter = 20000L,
      prune_tol = 1e-10,
      start_alpha = 0.1,
      info_rcond = 1e-4
    )
  )
  list(estimate = as.numeric(stats::coef(fit)[["alpha"]]),
       se = se_from_fit(fit), iter = NA_integer_)
}

fit_normal_fiml <- function(X) {
  X_num <- matrix(as.numeric(X), nrow = nrow(X), ncol = ncol(X))
  fit <- misskappa::alpha_continuous(
    X_num,
    se_type = "sandwich",
    em_options = list(tol = 1e-8, max_iter = 10000L, fd_h = 1e-5)
  )
  list(
    estimate = as.numeric(stats::coef(fit)[["alpha"]]),
    se = se_from_fit(fit),
    iter = fit$moments$iterations
  )
}

fit_listwise <- function(X) {
  cc <- stats::complete.cases(X)
  if (sum(cc) < ncol(X)) stop("too few complete rows for listwise alpha.")
  fit <- misskappa::alpha(X[cc, , drop = FALSE], method = "available")
  list(estimate = as.numeric(stats::coef(fit)[["alpha"]]),
       se = se_from_fit(fit), iter = NA_integer_)
}

fit_one <- function(X, method) {
  start <- proc.time()[["elapsed"]]
  out <- tryCatch({
    ans <- switch(
      method,
      pairwise = fit_pairwise(X),
      cat_fiml = fit_cat_fiml(X),
      normal_fiml = fit_normal_fiml(X),
      listwise = fit_listwise(X)
    )
    ans$error <- ""
    ans
  }, error = function(e) {
    list(estimate = NA_real_, se = NA_real_, iter = NA_integer_,
         error = conditionMessage(e))
  })
  out$elapsed_ms <- 1000 * (proc.time()[["elapsed"]] - start)
  out
}

min_pair_count <- function(X) {
  p <- ncol(X)
  counts <- integer(p * (p - 1L) / 2L)
  idx <- 0L
  for (j in seq_len(p - 1L)) {
    for (k in (j + 1L):p) {
      idx <- idx + 1L
      counts[idx] <- sum(!is.na(X[, j]) & !is.na(X[, k]))
    }
  }
  min(counts)
}

row_seed <- function(cell, rep_id) opts$seed_base + 1000000L * cell + rep_id

truth_rows <- do.call(rbind, lapply(opts$dgps, function(name) {
  spec <- dgp_defs[[name]]
  Sigma <- spec$sigma()
  eig <- eigen(Sigma, symmetric = TRUE, only.values = TRUE)$values
  data.frame(
    dgp = name,
    dgp_label = spec$label,
    family = spec$family,
    p = ncol(Sigma),
    categories = spec$categories,
    truth_alpha = alpha_from_sigma(Sigma),
    min_score_cov = min(Sigma[upper.tri(Sigma)]),
    max_score_cov = max(Sigma[upper.tri(Sigma)]),
    min_sigma_eigen = min(eig),
    dgp_note = if (identical(name, "class_skew")) {
      "Two-class ordinal mixture, conditionally independent items within class"
    } else if (identical(name, "anchor_heterocov")) {
      "Item 1 indexes groups with different target-item means and target covariance"
    } else {
      paste0("Thresholded congeneric Gaussian copula, margins ",
             paste(spec$probs, collapse = "/"))
    },
    stringsAsFactors = FALSE
  )
}))

truth_for <- function(dgp) truth_rows$truth_alpha[match(dgp, truth_rows$dgp)]

split_keys <- function(data, keys) interaction(data[, keys], drop = TRUE, lex.order = TRUE)

summarize_replicates <- function(df) {
  keys <- c("dgp", "dgp_label", "family", "p", "mechanism", "n", "method")
  out <- lapply(split(df, split_keys(df, keys)), function(g) {
    ok <- is.finite(g$estimate)
    se_ok <- ok & is.finite(g$se) & g$se > 0
    err <- g$estimate - g$truth
    z <- err[se_ok] / g$se[se_ok]
    cov95 <- abs(err[se_ok]) <= stats::qnorm(0.975) * g$se[se_ok]
    data.frame(
      dgp = g$dgp[[1L]],
      dgp_label = g$dgp_label[[1L]],
      family = g$family[[1L]],
      p = g$p[[1L]],
      mechanism = g$mechanism[[1L]],
      n = g$n[[1L]],
      method = g$method[[1L]],
      reps = length(unique(g$rep)),
      n_valid = sum(ok),
      failures = sum(!ok),
      truth = g$truth[[1L]],
      mean_estimate = if (any(ok)) mean(g$estimate[ok]) else NA_real_,
      bias = if (any(ok)) mean(err[ok]) else NA_real_,
      sd_estimate = if (sum(ok) > 1L) stats::sd(g$estimate[ok]) else NA_real_,
      mc_se_bias = if (sum(ok) > 1L) stats::sd(g$estimate[ok]) / sqrt(sum(ok)) else NA_real_,
      mse = if (any(ok)) mean(err[ok]^2) else NA_real_,
      mean_se = if (any(se_ok)) mean(g$se[se_ok]) else NA_real_,
      coverage95 = if (any(se_ok)) mean(cov95) else NA_real_,
      mean_z = if (length(z)) mean(z) else NA_real_,
      sd_z = if (length(z) > 1L) stats::sd(z) else NA_real_,
      mean_ci_length = if (any(se_ok)) mean(2 * stats::qnorm(0.975) * g$se[se_ok]) else NA_real_,
      mean_elapsed_ms = mean(g$elapsed_ms, na.rm = TRUE),
      median_elapsed_ms = stats::median(g$elapsed_ms, na.rm = TRUE),
      mean_observed_fraction = mean(g$observed_fraction, na.rm = TRUE),
      mean_complete_rows = mean(g$complete_rows, na.rm = TRUE),
      min_pair_count_min = min(g$min_pair_count, na.rm = TRUE),
      mean_em_iter = mean(g$em_iter, na.rm = TRUE),
      stringsAsFactors = FALSE
    )
  })
  ans <- do.call(rbind, out)
  ans$mechanism_order <- match(ans$mechanism, opts$mechanisms)
  ans$method_order <- match(ans$method, opts$methods)
  ans$dgp_order <- match(ans$dgp, opts$dgps)
  ans <- ans[order(ans$dgp_order, ans$mechanism_order, ans$method_order), ]
  rownames(ans) <- NULL
  ans
}

log_progress <- function(...) {
  if (opts$progress) message(format(Sys.time(), "%H:%M:%S"), " ", sprintf(...))
}

grid <- expand.grid(
  dgp = opts$dgps,
  mechanism = opts$mechanisms,
  n = opts$n,
  stringsAsFactors = FALSE
)
grid <- grid[order(match(grid$dgp, opts$dgps), match(grid$mechanism, opts$mechanisms)), , drop = FALSE]

rep_rows <- list()
t0 <- Sys.time()
for (cell in seq_len(nrow(grid))) {
  dgp_name <- grid$dgp[cell]
  spec <- dgp_defs[[dgp_name]]
  truth <- truth_for(dgp_name)
  log_progress(
    "cell %d/%d: %s %s n=%d reps=%d",
    cell, nrow(grid), dgp_name, grid$mechanism[cell],
    grid$n[cell], opts$reps
  )
  for (rep_id in seq_len(opts$reps)) {
    set.seed(row_seed(cell, rep_id))
    X_star <- spec$simulate(grid$n[cell])
    colnames(X_star) <- paste0("y", seq_len(ncol(X_star)))
    X <- apply_missing(X_star, grid$mechanism[cell])
    observed_fraction <- mean(!is.na(X))
    complete_rows <- sum(stats::complete.cases(X))
    min_pair <- min_pair_count(X)
    for (method in opts$methods) {
      fit <- fit_one(X, method)
      rep_rows[[length(rep_rows) + 1L]] <- data.frame(
        dgp = dgp_name,
        dgp_label = spec$label,
        family = spec$family,
        p = ncol(X),
        mechanism = grid$mechanism[cell],
        n = grid$n[cell],
        rep = rep_id,
        seed = row_seed(cell, rep_id),
        method = method,
        truth = truth,
        estimate = fit$estimate,
        bias = fit$estimate - truth,
        se = fit$se,
        elapsed_ms = fit$elapsed_ms,
        em_iter = fit$iter,
        observed_fraction = observed_fraction,
        complete_rows = complete_rows,
        min_pair_count = min_pair,
        error = fit$error,
        stringsAsFactors = FALSE
      )
    }
  }
}

replicates <- if (length(rep_rows)) do.call(rbind, rep_rows) else data.frame()
summary <- summarize_replicates(replicates)

dir.create(opts$out_dir, recursive = TRUE, showWarnings = FALSE)
write.csv(truth_rows, file.path(opts$out_dir, "truth.csv"), row.names = FALSE)
write.csv(replicates, file.path(opts$out_dir, "replicates.csv"), row.names = FALSE)
write.csv(summary, file.path(opts$out_dir, "summary.csv"), row.names = FALSE)

metadata <- data.frame(
  key = c(
    "generated_at", "script", "smoke", "reps", "n", "dgps",
    "mechanisms", "methods", "seed_base", "elapsed_seconds",
    "stress_question", "misskappa_version", "r_version"
  ),
  value = c(
    format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    normalizePath(file.path(script_dir, "run_experiment.R"), mustWork = FALSE),
    as.character(opts$smoke),
    as.character(opts$reps),
    as.character(opts$n),
    paste(opts$dgps, collapse = ","),
    paste(opts$mechanisms, collapse = ","),
    paste(opts$methods, collapse = ","),
    as.character(opts$seed_base),
    as.character(round(as.numeric(difftime(Sys.time(), t0, units = "secs")), 3)),
    "Does normal FIML stay nearly unbiased for scored ordinal MAR after skewed margins, a latent-class ordinal DGP, and nonlinear anchor-dependent missingness?",
    as.character(utils::packageVersion("misskappa")),
    R.version.string
  ),
  stringsAsFactors = FALSE
)
write.csv(metadata, file.path(opts$out_dir, "metadata.csv"), row.names = FALSE)

message("Wrote:")
for (name in c("truth.csv", "replicates.csv", "summary.csv", "metadata.csv")) {
  message("  ", normalizePath(file.path(opts$out_dir, name), mustWork = FALSE))
}
